package cmd

import (
	"encoding/json"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) beadMigrator(s *bead.Store) (bead.Migrator, error) {
	return bead.NewMigrator(bead.MigratorOptions{Dir: s.Dir})
}

func (f *CommandFactory) newBeadMigrateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "migrate",
		Short: "Split active beads.jsonl into beads + beads-archive + attachments",
		Long: `Split the existing .ddx/beads.jsonl into the modern layout:

  * Closed beads' inline events are moved to per-bead sidecars under
    .ddx/attachments/<id>/events.jsonl (ADR-004).
  * Eligible closed beads are moved to .ddx/beads-archive.jsonl using a
    permissive archival policy (TD-027).

The command is idempotent — a second run with no further changes is a
no-op. All bead IDs remain addressable: 'ddx bead show', 'ddx bead list',
and 'ddx bead status' transparently consult the archive partner.

With --to axon, the command instead copies the entire JSONL corpus
(.ddx/beads.jsonl + .ddx/beads-archive.jsonl, including externalized
events) losslessly into the axon backend under .ddx/axon/. The source
JSONL files are not modified — the operator removes them after verifying
the migration via 'ddx bead export | diff'.`,
		Args: cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			s := f.beadStore()
			mig, err := f.beadMigrator(s)
			if err != nil {
				return err
			}
			dryRun, _ := cmd.Flags().GetBool("dry-run")
			applyLifecycle, _ := cmd.Flags().GetBool("apply")
			asJSON, _ := cmd.Flags().GetBool("json")
			lifecycle, _ := cmd.Flags().GetBool("lifecycle")
			target, _ := cmd.Flags().GetString("to")
			if applyLifecycle && !lifecycle {
				return fmt.Errorf("bead: --apply is only supported with --lifecycle")
			}
			if applyLifecycle && dryRun {
				return fmt.Errorf("bead: --apply and --dry-run are mutually exclusive")
			}

			if target != "" {
				if lifecycle {
					return fmt.Errorf("bead: --lifecycle cannot be combined with --to")
				}
				if target != "axon" {
					return fmt.Errorf("bead: unknown migration target %q (supported: axon)", target)
				}
				if dryRun {
					return fmt.Errorf("bead: --dry-run is not supported with --to axon")
				}
				ax, err := mig.MigrateToAxon(cmd.Context())
				if err != nil {
					return err
				}
				view := migrateAxonStatsView{
					BeadsMigrated:  ax.BeadsMigrated,
					EventsMigrated: ax.EventsMigrated,
					To:             "axon",
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(view)
				}
				out := cmd.OutOrStdout()
				fmt.Fprintf(out, "Migrated %d bead(s) (%d inline event(s)) to axon backend at .ddx/axon/\n", view.BeadsMigrated, view.EventsMigrated)
				fmt.Fprintln(out, "Source files left intact — remove .ddx/beads.jsonl and .ddx/beads-archive.jsonl after verifying.")
				return nil
			}

			if lifecycle {
				var (
					st  bead.LifecycleMigrationStats
					err error
				)
				if applyLifecycle {
					err = f.withBeadTrackerWriteLock(func() error {
						st, err = mig.MigrateLifecycle(cmd.Context())
						if err != nil {
							return err
						}
						if st.Changed() {
							paths := []string{s.File}
							if st.MarkerWritten {
								paths = append(paths, s.LifecycleSchemaMarkerPath())
							}
							if _, err := f.beadAutoCommitPaths("migrate lifecycle", paths); err != nil {
								return err
							}
						}
						return nil
					})
				} else {
					st, err = mig.MigrateLifecycleDryRun(cmd.Context())
				}
				if err != nil {
					return err
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(st)
				}
				out := cmd.OutOrStdout()
				if !applyLifecycle {
					fmt.Fprintln(out, "Dry run — no files were modified.")
				}
				fmt.Fprintf(out, "needs_human labels:                  %d\n", st.LegacyNeedsHumanLabels)
				fmt.Fprintf(out, "triage:needs-investigation labels:   %d\n", st.LegacyNeedsInvestigationLabels)
				fmt.Fprintf(out, "needs_investigation pseudo-statuses: %d\n", st.LegacyNeedsInvestigationPseudoStatuses)
				fmt.Fprintf(out, "legacy no_changes metadata rows:     %d\n", st.LegacyNoChangesMetadataRows)
				fmt.Fprintf(out, "to proposed:                         %d\n", st.ToProposed)
				fmt.Fprintf(out, "to open:                             %d\n", st.ToOpen)
				fmt.Fprintf(out, "to blocked:                          %d\n", st.ToBlocked)
				fmt.Fprintf(out, "to closed:                           %d\n", st.ToClosed)
				fmt.Fprintf(out, "to cancelled:                        %d\n", st.ToCancelled)
				fmt.Fprintf(out, "schema marker missing:               %t\n", st.SchemaMarkerMissing)
				if applyLifecycle {
					fmt.Fprintf(out, "rows changed:                        %d\n", st.RowsChanged)
					fmt.Fprintf(out, "marker written:                      %t\n", st.MarkerWritten)
					if !st.Changed() {
						fmt.Fprintln(out, "No changes — lifecycle migration already applied.")
					}
				}
				return nil
			}

			var (
				ext  int
				arch int
			)
			if dryRun {
				st, err := mig.MigrateDryRun(cmd.Context())
				if err != nil {
					return err
				}
				ext, arch = st.EventsExternalized, st.Archived
			} else {
				if err := f.withBeadTrackerWriteLock(func() error {
					st, err := s.Migrate(cmd.Context())
					if err != nil {
						return err
					}
					ext, arch = st.EventsExternalized, st.Archived
					if st.Changed() {
						if _, err := f.beadExternalizeArchiveAutoCommit(st); err != nil {
							return err
						}
					}
					return nil
				}); err != nil {
					return err
				}
			}
			stats := migrateStatsView{EventsExternalized: ext, Archived: arch, DryRun: dryRun}

			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(stats)
			}
			out := cmd.OutOrStdout()
			if dryRun {
				fmt.Fprintln(out, "Dry run — no files were modified.")
			}
			fmt.Fprintf(out, "Externalized events: %d\n", ext)
			fmt.Fprintf(out, "Archived beads:      %d\n", arch)
			if ext == 0 && arch == 0 {
				fmt.Fprintln(out, "No changes — already migrated.")
			}
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output as JSON")
	cmd.Flags().Bool("dry-run", false, "Report what would change without writing")
	cmd.Flags().Bool("lifecycle", false, "Migrate legacy lifecycle labels and pseudo-statuses to status-owned state")
	cmd.Flags().Bool("apply", false, "Apply --lifecycle migration (default with --lifecycle is dry-run)")
	cmd.Flags().String("to", "", "Migrate corpus to a different backend (supported: axon)")
	return cmd
}

type migrateStatsView struct {
	EventsExternalized int  `json:"EventsExternalized"`
	Archived           int  `json:"Archived"`
	DryRun             bool `json:"DryRun,omitempty"`
}

type migrateAxonStatsView struct {
	BeadsMigrated  int    `json:"BeadsMigrated"`
	EventsMigrated int    `json:"EventsMigrated"`
	To             string `json:"To"`
}

package bead

import (
	"context"
	"fmt"
	"time"
)

// Migrator provides admin/one-shot migration operations on a bead store.
// These operations are not part of the steady-state Backend interface.
type Migrator interface {
	MigrateLifecycle(ctx context.Context) (LifecycleMigrationStats, error)
	MigrateLifecycleDryRun(ctx context.Context) (LifecycleMigrationStats, error)
	MigrateFromHelix(ctx context.Context) (int, bool, error)
	MigrateToAxon(ctx context.Context) (MigrateAxonStats, error)
	MigrateDryRun(ctx context.Context) (MigrateStats, error)
	DetectLifecycleMigrationRequired(ctx context.Context) (LifecycleMigrationGateStatus, error)
	ReconcileLifecycleMetadata(ctx context.Context, opts ReconcileOptions) ([]ReconcilePlan, error)
}

// MigratorOptions configures NewMigrator.
type MigratorOptions struct {
	Dir string
}

type storeMigrator struct {
	store *Store
}

// Compile-time assertion: *storeMigrator satisfies Migrator.
var _ Migrator = (*storeMigrator)(nil)

// NewMigrator returns a Migrator backed by the store at opts.Dir.
func NewMigrator(opts MigratorOptions) (Migrator, error) {
	return &storeMigrator{store: NewStore(opts.Dir)}, nil
}

func (m *storeMigrator) MigrateLifecycle(_ context.Context) (LifecycleMigrationStats, error) {
	return m.store.migrateLifecycle(true, time.Now().UTC())
}

func (m *storeMigrator) MigrateLifecycleDryRun(_ context.Context) (LifecycleMigrationStats, error) {
	return m.store.migrateLifecycle(false, time.Now().UTC())
}

func (m *storeMigrator) MigrateDryRun(_ context.Context) (MigrateStats, error) {
	return m.store.migrateDryRun()
}

func (m *storeMigrator) MigrateFromHelix(_ context.Context) (int, bool, error) {
	return m.store.migrateFromHelix()
}

// MigrateToAxon is deprecated. The JSONL-to-axon copy will be replaced by the
// importer in the ddx-IMP bead. This method always returns ErrDeprecated.
func (m *storeMigrator) MigrateToAxon(_ context.Context) (MigrateAxonStats, error) {
	return MigrateAxonStats{}, fmt.Errorf("%w: MigrateToAxon is replaced by the importer in ddx-IMP", ErrDeprecated)
}

func (m *storeMigrator) DetectLifecycleMigrationRequired(_ context.Context) (LifecycleMigrationGateStatus, error) {
	return m.store.detectLifecycleMigrationRequired()
}

func (m *storeMigrator) ReconcileLifecycleMetadata(_ context.Context, opts ReconcileOptions) ([]ReconcilePlan, error) {
	return m.store.reconcileLifecycleMetadata(opts)
}

package bead

import (
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// migrateSeed builds a closed bead with inline events and an updated
// timestamp far enough in the past that any future MinAge check would
// also accept it. Migrate uses MinAge=0 internally so the timestamp only
// matters for its archived_at stamp.
func migrateSeed(id, title string, withEvents bool) Bead {
	t := time.Now().UTC().Add(-90 * 24 * time.Hour)
	b := Bead{
		ID:        id,
		Title:     title,
		Status:    StatusClosed,
		Priority:  2,
		IssueType: DefaultType,
		CreatedAt: t.Add(-time.Hour),
		UpdatedAt: t,
	}
	if withEvents {
		b.Extra = map[string]any{
			"events": []map[string]any{
				{"kind": "review", "summary": "APPROVE", "body": "ok", "created_at": t.Format(time.RFC3339Nano)},
				{"kind": "summary", "summary": "done", "body": "", "created_at": t.Format(time.RFC3339Nano)},
			},
			"closing_commit_sha": "deadbeef",
		}
	} else {
		b.Extra = map[string]any{"closing_commit_sha": "deadbeef"}
	}
	return b
}

func TestMigrateExternalizesAndArchives(t *testing.T) {
	s := newTestStore(t)
	require.NoError(t, s.WriteAll([]Bead{
		migrateSeed("ddx-c1", "closed with events", true),
		migrateSeed("ddx-c2", "closed without events", false),
		{
			ID:        "ddx-open",
			Title:     "still open",
			Status:    StatusOpen,
			Priority:  2,
			IssueType: DefaultType,
			CreatedAt: time.Now().UTC().Add(-time.Hour),
			UpdatedAt: time.Now().UTC(),
		},
	}))

	stats, err := s.Migrate(testCtx())
	require.NoError(t, err)
	assert.Equal(t, 1, stats.EventsExternalized, "only ddx-c1 had inline events")
	assert.Equal(t, 2, stats.Archived, "both closed beads should archive")

	// AC2: archive file exists, attachments dir populated.
	archivePath := filepath.Join(s.Dir, BeadsArchiveCollection+".jsonl")
	info, statErr := os.Stat(archivePath)
	require.NoError(t, statErr)
	assert.Greater(t, info.Size(), int64(0))

	attachPath := s.eventsAttachmentPath("ddx-c1")
	_, statErr = os.Stat(attachPath)
	require.NoError(t, statErr, "events sidecar must exist for ddx-c1")

	// Active collection only contains the open bead.
	active, err := s.ReadAll(testCtx())
	require.NoError(t, err)
	require.Len(t, active, 1)
	assert.Equal(t, "ddx-open", active[0].ID)
}

func TestMigrateIsIdempotent(t *testing.T) {
	s := newTestStore(t)
	require.NoError(t, s.WriteAll([]Bead{
		migrateSeed("ddx-c1", "closed", true),
		migrateSeed("ddx-c2", "closed", false),
	}))

	first, err := s.Migrate(testCtx())
	require.NoError(t, err)
	assert.True(t, first.Changed())

	beforeActive, err := os.ReadFile(s.File)
	require.NoError(t, err)
	beforeArchive, err := os.ReadFile(filepath.Join(s.Dir, BeadsArchiveCollection+".jsonl"))
	require.NoError(t, err)

	second, err := s.Migrate(testCtx())
	require.NoError(t, err)
	assert.False(t, second.Changed(), "second pass must be a no-op")

	afterActive, err := os.ReadFile(s.File)
	require.NoError(t, err)
	afterArchive, err := os.ReadFile(filepath.Join(s.Dir, BeadsArchiveCollection+".jsonl"))
	require.NoError(t, err)
	assert.Equal(t, string(beforeActive), string(afterActive), "active file must not change on second pass")
	assert.Equal(t, string(beforeArchive), string(afterArchive), "archive file must not change on second pass")
}

func TestMigratePreservesData(t *testing.T) {
	s := newTestStore(t)
	beads := []Bead{
		migrateSeed("ddx-c1", "with events", true),
		migrateSeed("ddx-c2", "no events", false),
		{
			ID:        "ddx-open",
			Title:     "open",
			Status:    StatusOpen,
			Priority:  2,
			IssueType: DefaultType,
			CreatedAt: time.Now().UTC().Add(-time.Hour),
			UpdatedAt: time.Now().UTC(),
		},
	}
	require.NoError(t, s.WriteAll(beads))

	beforeStatus, err := s.Status()
	require.NoError(t, err)

	_, err = s.Migrate(testCtx())
	require.NoError(t, err)

	afterStatus, err := s.Status()
	require.NoError(t, err)
	// AC3: totals identical pre/post migration.
	assert.Equal(t, beforeStatus.Total, afterStatus.Total)
	assert.Equal(t, beforeStatus.Open, afterStatus.Open)
	assert.Equal(t, beforeStatus.Closed, afterStatus.Closed)
	assert.Equal(t, beforeStatus.Ready, afterStatus.Ready)
	assert.Equal(t, beforeStatus.Blocked, afterStatus.Blocked)

	// AC4: show works for archived beads.
	for _, want := range []string{"ddx-c1", "ddx-c2", "ddx-open"} {
		got, err := s.GetWithArchive(testCtx(), want)
		require.NoError(t, err, "GetWithArchive(%s)", want)
		require.NotNil(t, got)
		assert.Equal(t, want, got.ID)
	}

	// Events for ddx-c1 are still readable from the sidecar attachment,
	// independent of which collection currently owns the row.
	ev, err := s.readEventsAttachment("ddx-c1")
	require.NoError(t, err)
	require.Len(t, ev, 2)
	assert.Equal(t, "review", ev[0].Kind)
	assert.Equal(t, "APPROVE", ev[0].Summary)
}

func TestMigrateDryRunReportsWithoutWriting(t *testing.T) {
	s := newTestStore(t)
	require.NoError(t, s.WriteAll([]Bead{
		migrateSeed("ddx-c1", "closed with events", true),
		migrateSeed("ddx-c2", "closed without events", false),
		{
			ID:        "ddx-open",
			Title:     "open",
			Status:    StatusOpen,
			Priority:  2,
			IssueType: DefaultType,
			CreatedAt: time.Now().UTC().Add(-time.Hour),
			UpdatedAt: time.Now().UTC(),
		},
	}))

	beforeActive, err := os.ReadFile(s.File)
	require.NoError(t, err)
	archivePath := filepath.Join(s.Dir, BeadsArchiveCollection+".jsonl")
	_, archiveStatErr := os.Stat(archivePath)
	require.True(t, os.IsNotExist(archiveStatErr), "archive should not exist before migrate")

	stats, err := (&storeMigrator{store: s}).MigrateDryRun(testCtx())
	require.NoError(t, err)
	assert.Equal(t, 1, stats.EventsExternalized)
	assert.Equal(t, 2, stats.Archived)

	afterActive, err := os.ReadFile(s.File)
	require.NoError(t, err)
	assert.Equal(t, string(beforeActive), string(afterActive), "dry-run must not touch active file")
	_, archiveStatErr = os.Stat(archivePath)
	assert.True(t, os.IsNotExist(archiveStatErr), "dry-run must not create archive file")
	_, attachStatErr := os.Stat(s.eventsAttachmentPath("ddx-c1"))
	assert.True(t, os.IsNotExist(attachStatErr), "dry-run must not create attachments")
}

// TestMigrateLargeFixtureSplits seeds a synthetic >5MB beads.jsonl mostly
// composed of closed beads with inline events, runs Migrate, and asserts
// that the active file shrinks below 4MB while the archive partner picks
// up the closed rows and per-bead attachments are written.
func TestMigrateLargeFixtureSplits(t *testing.T) {
	s := newTestStore(t)

	// Build ~600 closed beads each carrying a chunky inline event so the
	// raw active file lands above the 4MB archive threshold.
	old := time.Now().UTC().Add(-90 * 24 * time.Hour)
	body := strings.Repeat("x", 8*1024) // 8KB body per event
	beads := make([]Bead, 0, 605)
	for i := 0; i < 600; i++ {
		beads = append(beads, Bead{
			ID:        fmt.Sprintf("ddx-l%04d", i),
			Title:     "closed with bulky event",
			Status:    StatusClosed,
			Priority:  2,
			IssueType: DefaultType,
			CreatedAt: old.Add(-time.Hour),
			UpdatedAt: old,
			Extra: map[string]any{
				"events": []map[string]any{
					{"kind": "summary", "summary": "done", "body": body, "created_at": old.Format(time.RFC3339Nano)},
				},
				"closing_commit_sha": "deadbeef",
			},
		})
	}
	for i := 0; i < 5; i++ {
		beads = append(beads, Bead{
			ID:        fmt.Sprintf("ddx-o%d", i),
			Title:     "open",
			Status:    StatusOpen,
			Priority:  2,
			IssueType: DefaultType,
			CreatedAt: time.Now().UTC().Add(-time.Hour),
			UpdatedAt: time.Now().UTC(),
		})
	}
	require.NoError(t, s.WriteAll(beads))

	info, err := os.Stat(s.File)
	require.NoError(t, err)
	require.Greater(t, info.Size(), int64(4*1024*1024), "fixture must exceed 4MB to be a meaningful split test")

	stats, err := s.Migrate(testCtx())
	require.NoError(t, err)
	assert.Equal(t, 600, stats.Archived)
	assert.Equal(t, 600, stats.EventsExternalized)

	// AC2: active file < 4MB after migration.
	info, err = os.Stat(s.File)
	require.NoError(t, err)
	assert.Less(t, info.Size(), int64(4*1024*1024), "active beads.jsonl must drop below 4MB after migration")

	// AC2: archive partner exists with the moved rows.
	archInfo, err := os.Stat(filepath.Join(s.Dir, BeadsArchiveCollection+".jsonl"))
	require.NoError(t, err)
	assert.Greater(t, archInfo.Size(), int64(0))

	// AC2: per-bead attachment sidecars exist for archived beads.
	_, err = os.Stat(s.eventsAttachmentPath("ddx-l0000"))

	_, err = os.Stat(s.eventsAttachmentPath("ddx-l0000"))
	require.NoError(t, err)

	// AC3 / AC6: re-running is a no-op.
	second, err := s.Migrate(testCtx())
	require.NoError(t, err)
	assert.False(t, second.Changed())
}

func loadMigrateToAxonFixture(t *testing.T) (*Store, bytes.Buffer) {
	t.Helper()
	dir := filepath.Join(t.TempDir(), ddxroot.DirName)
	require.NoError(t, os.MkdirAll(dir, 0o755))

	copyFixture := func(src, dst string) {
		t.Helper()
		data, err := os.ReadFile(src)
		require.NoError(t, err)
		require.NoError(t, os.WriteFile(dst, data, 0o644))
	}
	copyFixture("testdata/migrate_axon_active.jsonl", filepath.Join(dir, "beads.jsonl"))
	copyFixture("testdata/migrate_axon_archive.jsonl", filepath.Join(dir, "beads-archive.jsonl"))

	jsonlStore := NewStore(dir)

	var preBuf bytes.Buffer
	require.NoError(t, jsonlStore.ExportTo(testCtx(), &preBuf))
	require.NotZero(t, preBuf.Len(), "fixture must produce a non-empty pre-migration export")
	return jsonlStore, preBuf
}

// TestMigrate_AxonBackend_RoundTrip verifies that the fixture pair
// (.ddx/beads.jsonl + .ddx/beads-archive.jsonl) migrates to axon and that a
// post-migration export matches the pre-migration JSONL export bead-for-bead
// (sorted to ignore active-then-archive ordering quirks in ExportTo).
func TestMigrate_AxonBackend_RoundTrip(t *testing.T) {
	jsonlStore, preBuf := loadMigrateToAxonFixture(t)

	stats, err := jsonlStore.migrateToAxon()
	require.NoError(t, err)
	// 3 active + 2 archive (no overlap) = 5 distinct beads.
	assert.Equal(t, 5, stats.BeadsMigrated)
	// 2 inline events on ddx-mta-active2 + 1 on ddx-mta-active3 + 1 on
	// ddx-mta-arch1 = 4 inline events written into ddx_bead_events.
	assert.Equal(t, 4, stats.EventsMigrated)

	// Source files left intact — operator removes them after verification.
	for _, src := range []string{"beads.jsonl", "beads-archive.jsonl"} {
		_, statErr := os.Stat(filepath.Join(jsonlStore.Dir, src))
		assert.NoError(t, statErr, "source file %s must not be deleted by migration", src)
	}
	// Axon collection files exist.
	for _, dst := range []string{"axon/ddx_beads.jsonl", "axon/ddx_bead_events.jsonl"} {
		_, statErr := os.Stat(filepath.Join(jsonlStore.Dir, dst))
		assert.NoError(t, statErr, "axon file %s must exist after migration", dst)
	}

	// Axon-backed export must match the JSONL export.
	axStore := NewStore(jsonlStore.Dir)
	axStore.backend = NewAxonBackend(jsonlStore.Dir, axStore.LockWait)
	var postBuf bytes.Buffer
	require.NoError(t, axStore.ExportTo(testCtx(), &postBuf))

	pre := sortedNonEmptyLines(preBuf.String())
	post := sortedNonEmptyLines(postBuf.String())
	assert.Equal(t, pre, post, "post-migration export must round-trip the pre-migration export")
}

// TestMigrate_AxonBackend_Idempotent verifies that a second migration pass on
// the same fixture is a no-op at the axon file level.
func TestMigrate_AxonBackend_Idempotent(t *testing.T) {
	jsonlStore, _ := loadMigrateToAxonFixture(t)
	stats, err := jsonlStore.migrateToAxon()
	require.NoError(t, err)

	axBeadsBefore, err := os.ReadFile(filepath.Join(jsonlStore.Dir, "axon", "ddx_beads.jsonl"))
	require.NoError(t, err)
	axEventsBefore, err := os.ReadFile(filepath.Join(jsonlStore.Dir, "axon", "ddx_bead_events.jsonl"))
