611	// MigrateAxonStats reports what MigrateToAxon copied in a single pass.
612	type MigrateAxonStats struct {
613		// BeadsMigrated is the total number of distinct bead IDs written into
614		// the axon backend (active + archive, deduped on ID).
615		BeadsMigrated int
616		// EventsMigrated is the total number of inline events written into the
617		// ddx_bead_events collection. Externalized events (referenced via
618		// Extra[events_attachment]) are not counted because they are not
619		// rewritten by the migration — the attachment file remains canonical.
620		EventsMigrated int
621	}
622	
623	// migrateToAxon reads beads from the JSONL active collection
624	// (.ddx/beads.jsonl) and the JSONL archive partner
625	// (.ddx/beads-archive.jsonl) rooted under s.Dir and writes them losslessly
626	// into the axon backend (.ddx/axon/). Source files are not modified.
627	//
628	// Reads always go through fresh JSONL backends regardless of s.backend so
629	// the migration is deterministic and not affected by the operator's
630	// configured backend (e.g. an axon-misconfigured store still migrates from
631	// the on-disk JSONL files). Active wins on duplicate IDs.
632	//
633	// Idempotent: AxonBackend.WriteAll overwrites both collection files in
634	// temp+rename style, so re-running on the same source state produces an
635	// identical axon snapshot with no duplicates.
636	func (s *Store) migrateToAxon() (MigrateAxonStats, error) {
637		var stats MigrateAxonStats
638	
639		activeSpec := DefaultRegistry().Resolve(DefaultCollection)
640		activeFile, activeLock := activeSpec.PathsUnder(s.Dir)
641		activeBackend := NewJSONLBackend(s.Dir, activeFile, activeLock, s.LockWait)
642	
643		archiveSpec := DefaultRegistry().Resolve(BeadsArchiveCollection)
644		archiveFile, archiveLock := archiveSpec.PathsUnder(s.Dir)
645		archiveBackend := NewJSONLBackend(s.Dir, archiveFile, archiveLock, s.LockWait)
646	
647		activeBeads, err := activeBackend.ReadAll()
648		if err != nil {
649			return stats, fmt.Errorf("bead: migrate-to-axon read active: %w", err)
650		}
651		archiveBeads, err := archiveBackend.ReadAll()
652		if err != nil {
653			return stats, fmt.Errorf("bead: migrate-to-axon read archive: %w", err)
654		}
655	
656		seen := make(map[string]bool, len(activeBeads))
657		merged := make([]Bead, 0, len(activeBeads)+len(archiveBeads))
658		for _, b := range activeBeads {
659			seen[b.ID] = true
660			merged = append(merged, b)
661		}
662		for _, b := range archiveBeads {
663			if seen[b.ID] {
664				continue
665			}
666			seen[b.ID] = true
667			merged = append(merged, b)
668		}
669	
670		for i := range merged {
671			stats.BeadsMigrated++
672			if hasInlineEvents(&merged[i]) {
673				stats.EventsMigrated += len(decodeBeadEvents(merged[i].Extra["events"]))
674			}
675		}
676	
677		if err := writeAxonSnapshotFiles(s.Dir, merged); err != nil {
678			return stats, fmt.Errorf("bead: migrate-to-axon write: %w", err)
679		}
680		return stats, nil
681	}
