683	func writeAxonSnapshotFiles(dir string, beads []Bead) error {
684		root := filepath.Join(dir, AxonDirName)
685		beadsFile := filepath.Join(root, AxonBeadsCollection+".jsonl")
686		eventsFile := filepath.Join(root, AxonEventsCollection+".jsonl")
687		if err := os.MkdirAll(root, 0o755); err != nil {
688			return fmt.Errorf("bead: axon mkdir: %w", err)
689		}
690		sort.Slice(beads, func(i, j int) bool { return beads[i].ID < beads[j].ID })
691	
692		var beadsBuf, eventsBuf bytes.Buffer
693		for _, b := range beads {
694			var events []BeadEvent
695			if b.Extra != nil {
696				if raw, ok := b.Extra["events"]; ok {
697					events = decodeBeadEvents(raw)
698				}
699			}
700			stripped := beadWithoutInlineEvents(b)
701			row, err := axonEncodeBead(stripped)
702			if err != nil {
703				return fmt.Errorf("bead: axon marshal %s: %w", b.ID, err)
704			}
705			beadsBuf.Write(row)
706			beadsBuf.WriteByte('\n')
707	
708			for i, ev := range events {
709				data, err := axonEncodeEvent(b.ID, i, ev)
710				if err != nil {
711					return fmt.Errorf("bead: axon marshal event %s/%d: %w", b.ID, i, err)
712				}
713				eventsBuf.Write(data)
714				eventsBuf.WriteByte('\n')
715			}
716		}
717	
718		if err := writeAtomicFile(eventsFile, eventsBuf.Bytes()); err != nil {
719			return fmt.Errorf("bead: axon write events: %w", err)
720		}
